mapper.select:
SELECT hr.id, hr.employee_id, hr.heart_rate, hr.measure_time, hr.is_abnormal, hr.source,
       e.name AS employee_name, e.position AS job
FROM employee_heart_rate hr
LEFT JOIN employee e ON hr.employee_id = e.id


        AND hr.employee_id = #{employeeId}


        AND hr.is_abnormal = #{isAbnormal}


        AND hr.measure_time >= #{startTime}


        AND hr.measure_time <= #{endTime}


ORDER BY hr.measure_time DESC
